code = """import json

# Load H2 2019 CPC groups from previous analysis
h2_2019_data = locals()['var_functions.execute_python:22']
h2_2019_cpc_groups = set(h2_2019_data['unique_cpc_groups'])
print('CPC groups found in H2 2019 German patents:', len(h2_2019_cpc_groups))

# Load EMA analysis results
ema_data = locals()['var_functions.execute_python:16']

# Load CPC definitions
cpc_definitions = locals()['var_functions.query_db:26']

# Create a dictionary of CPC definitions
cpc_def_dict = {}
for item in cpc_definitions:
    cpc_def_dict[item['symbol']] = item['titleFull']

print('Available CPC definitions:', len(cpc_def_dict))

# Filter EMA results to only include CPC groups present in H2 2019
h2_2019_ema_results = []
for result in ema_data['top_groups_by_ema']:
    if result['cpc_group'] in h2_2019_cpc_groups:
        h2_2019_ema_results.append(result)

print('EMA results for H2 2019 CPC groups:', len(h2_2019_ema_results))

# Sort by EMA value
h2_2019_ema_results = sorted(h2_2019_ema_results, key=lambda x: x['best_year_ema'], reverse=True)

# Create final results with full titles
final_results = []
for result in h2_2019_ema_results[:20]:
    cpc_group = result['cpc_group']
    title = cpc_def_dict.get(cpc_group, 'Title not available')
    
    final_results.append({
        'cpc_group_code': cpc_group,
        'full_title': title,
        'best_year': result['best_year'],
        'best_year_patent_count': result['best_year_count'],
        'exponential_moving_average': round(result['best_year_ema'], 2),
        'total_german_patents': result['total_patents'],
        'years_active': result['years_active']
    })

print('\nTop CPC Technology Areas in Germany (H2 2019 Patents):')
for i, item in enumerate(final_results[:10], 1):
    print(f"{i}. {item['cpc_group_code']}: {item['full_title']}")
    print(f"   Best Year: {item['best_year']} (EMA: {item['exponential_moving_average']}, Count: {item['best_year_patent_count']})")

# Final output for user
result_text = "Top CPC Technology Areas in Germany with Highest Exponential Moving Average (2019 H2 Patents)\n\n"
result_text += "Based on analysis of German patents granted in the second half of 2019, here are the top CPC technology areas at level 4:\n\n"

for item in final_results:
    result_text += f"CPC Group {item['cpc_group_code']}: {item['full_title']}\n"
    result_text += f"  - Best Year: {item['best_year']} with {item['best_year_patent_count']} patents\n"
    result_text += f"  - Exponential Moving Average: {item['exponential_moving_average']:.2f}\n"
    result_text += f"  - Total German Patents (all years): {item['total_german_patents']}\n"
    result_text += f"  - Years Active: {item['years_active']}\n\n"

print('__RESULT__:')
print(json.dumps(result_text))"""

